 19→/// Arguments for jjx_show command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrpd_ParadeArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: std::path::PathBuf,
 25→
 26→    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
 27→    pub target: Option<String>,
 28→
 29→    /// Show paddock and full dockets (heat mode only)
 30→    #[arg(long)]
 31→    pub detail: bool,
 32→
 33→    /// Show only remaining paces (exclude complete/abandoned)
 34→    #[arg(long)]
 35→    pub remaining: bool,
 36→}
 37→
 38→/// Run the show command - display comprehensive Heat status
 39→pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs) -> i32 {
 40→    let gallops = match Gallops::jjrg_load(&args.file) {
 41→        Ok(g) => g,
 42→        Err(e) => {
 43→            eprintln!("jjx_show: error: {}", e);
 44→            return 1;
 45→        }
 46→    };
 47→
 48→    // Resolve target: use provided value or auto-select first racing heat
 49→    let target = match args.target {
 50→        Some(t) => t,
 51→        None => {
 52→            // Load gallops to resolve default heat
 53→            match zjjrpd_resolve_default_heat(&gallops) {
 54→                Ok(fm) => fm,
 55→                Err(e) => {
 56→                    eprintln!("jjx_show: error: {}", e);
 57→                    return 1;
 58→                }
 59→            }
 60→        }
 61→    };
 62→
 63→    // Determine target type by length
 64→    let target_str = target.strip_prefix('₢').or_else(|| target.strip_prefix('₣')).unwrap_or(&target);
 65→
 66→    if target_str.len() == 5 {
 67→        // Coronet - pace view
 68→        let coronet = match Coronet::jjrf_parse(&target) {
 69→            Ok(c) => c,
 70→            Err(e) => {
 71→                eprintln!("jjx_show: error: {}", e);
 72→                return 1;
 73→            }
 74→        };
 75→
 76→        // Extract parent firemark
 77→        let firemark = coronet.jjrf_parent_firemark();
 78→        let heat_key = firemark.jjrf_display();
 79→        let heat = match gallops.heats.get(&heat_key) {
 80→            Some(h) => h,
 81→            None => {
 82→                eprintln!("jjx_show: error: Heat '{}' not found", heat_key);
 83→                return 1;
 84→            }
 85→        };
 86→
 87→        // Find pace
 88→        let coronet_key = coronet.jjrf_display();
 89→        let pace = match heat.paces.get(&coronet_key) {
 90→            Some(p) => p,
 91→            None => {
 92→                eprintln!("jjx_show: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
 93→                return 1;
 94→            }
 95→        };
 96→
 97→        // Display tack history - iterate in reverse order (oldest first)
 98→        if !pace.tacks.is_empty() {
 99→            // Print header with current state from tacks[0]
100→            let current_tack = &pace.tacks[0];
101→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
102→            println!("Heat: {}", heat_key);
103→
104→            // Show work files touched by this pace's commits
105→            match jjrq_files_for_pace(firemark.jjrf_as_str(), &coronet_key) {
106→                Ok(files) if !files.is_empty() => {
107→                    println!("Work files: {}", files.join(", "));
108→                }
109→                _ => {}
110→            }
111→            println!();
112→
113→            // Iterate tacks in reverse order (oldest first)
114→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
115→                let state_str = zjjrpd_pace_state_str(&tack.state);
116→                let basis_str = if tack.basis == "0000000" {
117→                    "(no basis)".to_string()
118→                } else {
119→                    tack.basis.clone()
120→                };
121→
122→                println!("[{}] {} (basis: {})", index, state_str, basis_str);
123→                println!("    Silks: {}", tack.silks);
124→                if let Some(ref direction) = tack.direction {
125→                    println!("    Warrant: {}", direction);
126→                }
127→                println!();
128→                // Indent docket text
129→                for line in tack.text.lines() {
130→                    println!("    {}", line);
131→                }
132→                println!();
133→            }
134→
135→            // Append files-per-commit bitmap
136→            zjjrpd_print_pace_commits(&firemark, &coronet_key);
137→        }
138→    } else if target_str.len() == 2 {
139→        // Firemark - heat view
140→        let firemark = match Firemark::jjrf_parse(&target) {
141→            Ok(fm) => fm,
142→            Err(e) => {
143→                eprintln!("jjx_show: error: {}", e);
144→                return 1;
145→            }
146→        };
147→
148→        let heat_key = firemark.jjrf_display();
149→        let heat = match gallops.heats.get(&heat_key) {
150→            Some(h) => h,
151→            None => {
152→                eprintln!("jjx_show: error: Heat '{}' not found", heat_key);
153→                return 1;
154→            }
155→        };
156→
157→        if args.detail {
158→            // Detail view: paddock + all dockets
159→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
160→                Ok(content) => content,
161→                Err(e) => {
162→                    eprintln!("jjx_show: error reading paddock file '{}': {}", heat.paddock_file, e);
163→                    return 1;
164→                }
165→            };
166→
167→            let status_str = match heat.status {
168→                HeatStatus::Racing => "racing",
169→                HeatStatus::Stabled => "stabled",
170→                HeatStatus::Retired => "retired",
171→            };
172→
173→            println!("Heat: {} ({})", heat.silks, heat_key);
174→            println!("Status: {}", status_str);
175→            println!("Created: {}", heat.creation_time);
176→            println!();
177→            println!("## Paddock");
178→            println!();
179→            println!("{}", paddock_content);
180→            println!();
181→            println!("## Paces");
182→            println!();
183→
184→            for coronet_key in &heat.order {
185→                if let Some(pace) = heat.paces.get(coronet_key) {
186→                    if let Some(tack) = pace.tacks.first() {
187→                        // Skip complete/abandoned if --remaining
188→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
189→                            continue;
190→                        }
191→                        let state_str = zjjrpd_pace_state_str(&tack.state);
192→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
193→                        println!();
194→                        println!("{}", tack.text);
195→                        if let Some(ref direction) = tack.direction {
196→                            println!();
197→                            println!("**Warrant:** {}", direction);
198→                        }
199→                        println!();
200→                    }
201→                }
202→            }
203→        } else {
204→            // List view: numbered paces
205→            // If --remaining, output markdown format
206→            if args.remaining {
207→                let mut complete_count = 0;
208→                let mut abandoned_count = 0;
209→                let mut rough_count = 0;
210→                let mut bridled_count = 0;
211→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
212→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
213→
214→                for coronet_key in &heat.order {
215→                    if let Some(pace) = heat.paces.get(coronet_key) {
216→                        if let Some(tack) = pace.tacks.first() {
217→                            match tack.state {
218→                                PaceState::Complete => complete_count += 1,
219→                                PaceState::Abandoned => abandoned_count += 1,
220→                                PaceState::Rough => {
221→                                    rough_count += 1;
222→                                    remaining_paces.push((coronet_key, pace));
223→                                    if first_remaining_pace.is_none() {
224→                                        first_remaining_pace = Some((coronet_key, pace));
225→                                    }
226→                                }
227→                                PaceState::Bridled => {
228→                                    bridled_count += 1;
229→                                    remaining_paces.push((coronet_key, pace));
230→                                    if first_remaining_pace.is_none() {
231→                                        first_remaining_pace = Some((coronet_key, pace));
232→                                    }
233→                                }
234→                            }
235→                        }
236→                    }
237→                }
238→
239→                let status_str = match heat.status {
240→                    HeatStatus::Racing => "racing",
241→                    HeatStatus::Stabled => "stabled",
242→                    HeatStatus::Retired => "retired",
243→                };
244→
245→                let remaining_count = rough_count + bridled_count;
246→
247→                // Header line with heat info
248→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
249→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
250→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
251→                println!();
252→
253→                // Table with remaining paces
254→                if !remaining_paces.is_empty() {
255→                    // Set up table with column definitions
256→                    let mut table = jjrp_Table::jjrp_new(vec![
257→                        jjrp_Column::new("No", jjrp_Align::Right),
258→                        jjrp_Column::new("State", jjrp_Align::Left),
259→                        jjrp_Column::new("Pace", jjrp_Align::Left),
260→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
261→                    ]);
262→
263→                    // Measure all rows to compute column widths
264→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
265→                        if let Some(tack) = pace.tacks.first() {
266→                            let state_str = zjjrpd_pace_state_str(&tack.state);
267→                            table.jjrp_measure(&[
268→                                &(idx + 1).to_string(),
269→                                state_str,
