273→                        }
274→                    }
275→
276→                    // Print header and separator
277→                    table.jjrp_print_header();
278→                    table.jjrp_print_separator();
279→
280→                    // Print data rows
281→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
282→                        if let Some(tack) = pace.tacks.first() {
283→                            let state_str = zjjrpd_pace_state_str(&tack.state);
284→                            table.jjrp_print_row(&[
285→                                &(idx + 1).to_string(),
286→                                state_str,
287→                                &tack.silks,
288→                                coronet_key,
289→                            ]);
290→                        }
291→                    }
292→                    println!();
293→                }
294→
295→                // Next up callout
296→                if let Some((coronet_key, pace)) = first_remaining_pace {
297→                    if let Some(tack) = pace.tacks.first() {
298→                        let state_str = zjjrpd_pace_state_str(&tack.state);
