307→                let mut table = jjrp_Table::jjrp_new(vec![
308→                    jjrp_Column::new("No", jjrp_Align::Right),
309→                    jjrp_Column::new("State", jjrp_Align::Left),
310→                    jjrp_Column::new("Pace", jjrp_Align::Left),
311→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
312→                ]);
313→
314→                // Measure all rows to compute column widths
315→                let mut num = 0;
316→                for coronet_key in &heat.order {
317→                    if let Some(pace) = heat.paces.get(coronet_key) {
318→                        if let Some(tack) = pace.tacks.first() {
319→                            num += 1;
320→                            let state_str = zjjrpd_pace_state_str(&tack.state);
321→                            table.jjrp_measure(&[
322→                                &num.to_string(),
323→                                state_str,
324→                                &tack.silks,
325→                                coronet_key,
326→                            ]);
327→                        }
328→                    }
329→                }
330→
331→                // Print header and separator
332→                table.jjrp_print_header();
333→                table.jjrp_print_separator();
334→
335→                // Print data rows
336→                let mut num = 0;
337→                for coronet_key in &heat.order {
338→                    if let Some(pace) = heat.paces.get(coronet_key) {
339→                        if let Some(tack) = pace.tacks.first() {
340→                            num += 1;
341→                            let state_str = zjjrpd_pace_state_str(&tack.state);
342→                            table.jjrp_print_row(&[
343→                                &num.to_string(),
344→                                state_str,
345→                                &tack.silks,
346→                                coronet_key,
347→                            ]);
348→                        }
349→                    }
350→                }
351→            }
352→        }
353→
354→        // Always show file-touch bitmap and commit swim lanes after pace listing
