365→/// Format the file-touch bitmap for a heat as a String.
366→///
367→/// Uses shared query routines from jjrq_query to get file touches,
368→/// then formats as a bitmap with columns per pace and rows per file,
369→/// grouped by identical touch patterns.
370→pub fn jjrpd_format_file_bitmap(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
371→    let touches = jjrq_file_touches_for_heat(firemark.jjrf_as_str())?;
372→
373→    // Build pace columns: only paces with commits, in heat order
374→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
375→    for coronet_key in &heat.order {
376→        if !touches.coronets_with_commits.contains(coronet_key) {
377→            continue;
378→        }
379→        if let Some(pace) = heat.paces.get(coronet_key) {
380→            if let Some(tack) = pace.tacks.first() {
381→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
382→                if let Some(ch) = raw.chars().last() {
383→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
384→                }
385→            }
386→        }
387→    }
388→
389→    // Map coronet_display -> column index
390→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
391→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
392→        coronet_to_col.insert(coronet_display.clone(), idx);
393→    }
394→
395→    let total_cols = pace_columns.len();
396→
397→    // Build file -> touch vector from the shared query result
398→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
399→
400→    for (coronet, files) in &touches.pace_files {
401→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
402→            for filename in files {
403→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
404→                if col_idx < row.len() {
405→                    row[col_idx] = true;
406→                }
407→            }
408→        }
409→    }
410→
411→    let mut output = String::new();
412→
413→    if file_touches_map.is_empty() {
414→        writeln!(output, "File-touch bitmap: (no work file changes)").unwrap();
415→        return Ok(output);
416→    }
417→
418→    // Group files by identical touch pattern
419→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
420→    for (filename, pattern) in &file_touches_map {
421→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
422→    }
423→
424→    for files in pattern_groups.values_mut() {
425→        files.sort();
426→    }
427→
428→    // Header
429→    writeln!(output, "File-touch bitmap (x = pace commit touched file):").unwrap();
430→    writeln!(output).unwrap();
431→
432→    // Vertical legend
433→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
434→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
435→    }
436→    writeln!(output).unwrap();
437→
438→    // Column header line (terminal chars aligned with bitmap positions)
439→    let header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
440→    let header_line: String = header_chars.iter().collect();
441→    writeln!(output, "{}", header_line).unwrap();
442→
443→    // Sort patterns: more touches first, then lexicographic
444→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
445→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
446→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
447→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
448→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
449→    });
450→
451→    for (pattern, files) in &sorted_patterns {
452→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
453→        writeln!(output, "{} {}", bitmap, files.join(", ")).unwrap();
454→    }
455→
456→    Ok(output)
457→}
