459→/// Print the file-touch bitmap for a heat to stdout.
460→pub(crate) fn jjrpd_print_file_bitmap(firemark: &Firemark, heat: &Heat) {
461→    match jjrpd_format_file_bitmap(firemark, heat) {
462→        Ok(output) => print!("{}", output),
463→        Err(e) => eprintln!("jjx_show: error getting file touches: {}", e),
464→    }
465→}
