467→/// Helper to convert PaceState to display string
468→pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
469→    match state {
470→        PaceState::Rough => "rough",
471→        PaceState::Bridled => "bridled",
472→        PaceState::Complete => "complete",
473→        PaceState::Abandoned => "abandoned",
474→    }
475→}
