477→/// Resolve the default heat (first racing heat) when no target is specified
478→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
479→    for (heat_key, heat) in &gallops.heats {
480→        if heat.status == HeatStatus::Racing {
481→            return Ok(heat_key.clone());
482→        }
483→    }
484→    Err("No racing heats found".to_string())
485→}
