487→/// Encode a column index as a dense character: 1-9 then a-z then A-Z (61 max)
488→fn zjjrpd_commit_index_char(index: usize) -> Option<char> {
489→    match index {
490→        0..=8 => Some((b'1' + index as u8) as char),
491→        9..=34 => Some((b'a' + (index - 9) as u8) as char),
492→        35..=60 => Some((b'A' + (index - 35) as u8) as char),
493→        _ => None,
494→    }
495→}
