497→/// Format commit swim lanes for a heat as a String: paces × commits matrix.
498→///
499→/// Shows when work happened on each pace and how work interleaved.
500→pub fn jjrpd_format_commit_swimlanes(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
501→    let rein_args = jjrs_ReinArgs {
502→        firemark: firemark.jjrf_as_str().to_string(),
503→        limit: 10000,
504→    };
505→
506→    let entries = jjrs_get_entries(&rein_args)?;
507→
508→    if entries.is_empty() {
509→        return Ok(String::new());
510→    }
511→
512→    // Entries are newest-first; truncate to 35 most recent, then reverse for chronological
513→    let total_commits = entries.len();
514→    let max_commits: usize = 35;
515→    let truncated = total_commits > max_commits;
516→    let display_entries: Vec<&jjrs_SteeplechaseEntry> = entries
517→        .iter()
518→        .take(max_commits)
519→        .collect::<Vec<_>>()
520→        .into_iter()
521→        .rev()
522→        .collect();
523→
524→    // Build pace rows: ordered by first chronological appearance
525→    let mut pace_order: Vec<(String, char, String)> = Vec::new(); // (coronet_display, term_char, silks)
526→    let mut pace_index: BTreeMap<String, usize> = BTreeMap::new();
527→
528→    for entry in &display_entries {
529→        if let Some(ref coronet) = entry.coronet {
530→            if !pace_index.contains_key(coronet) {
531→                let idx = pace_order.len();
532→                let raw = coronet.strip_prefix('₢').unwrap_or(coronet);
533→                let ch = raw.chars().last().unwrap_or('?');
534→                let silks = heat.paces.get(coronet)
535→                    .and_then(|p| p.tacks.first())
536→                    .map(|t| t.silks.clone())
537→                    .unwrap_or_else(|| "unknown".to_string());
538→                pace_index.insert(coronet.clone(), idx);
539→                pace_order.push((coronet.clone(), ch, silks));
540→            }
541→        }
542→        // heat-level entries (no coronet) are intentionally excluded from swim lanes
543→    }
544→
545→    let total_rows = pace_order.len();
546→
547→    if total_rows == 0 {
548→        return Ok(String::new());
549→    }
550→
551→    // Build bitmap: rows × columns
552→    let num_cols = display_entries.len();
553→    let mut bitmap: Vec<Vec<bool>> = vec![vec![false; num_cols]; total_rows];
554→    let mut row_commit_counts: Vec<usize> = vec![0; total_rows];
555→
556→    for (col, entry) in display_entries.iter().enumerate() {
557→        if let Some(ref coronet) = entry.coronet {
558→            if let Some(&row) = pace_index.get(coronet) {
559→                bitmap[row][col] = true;
560→                row_commit_counts[row] += 1;
561→            }
562→        }
563→        // heat-level entries (no coronet) are intentionally excluded from swim lanes
564→    }
565→
566→    let mut output = String::new();
567→
568→    writeln!(output).unwrap();
569→    writeln!(output, "Commit swim lanes (x = commit affiliated with pace):").unwrap();
570→    writeln!(output).unwrap();
571→
572→    if truncated {
