605→/// Print files-per-commit bitmap for a single pace.
606→///
607→/// Shows which files each commit in this pace touched.
608→/// Called after tack history in pace parade.
609→fn zjjrpd_print_pace_commits(firemark: &Firemark, coronet_key: &str) {
610→    let rein_args = jjrs_ReinArgs {
611→        firemark: firemark.jjrf_as_str().to_string(),
612→        limit: 10000,
613→    };
614→
615→    let entries = match jjrs_get_entries(&rein_args) {
616→        Ok(e) => e,
617→        Err(e) => {
618→            eprintln!("jjx_show: error getting steeplechase entries: {}", e);
619→            return;
620→        }
621→    };
622→
623→    // Filter by coronet, then reverse for chronological order
624→    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
625→        .iter()
626→        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
627→        .collect::<Vec<_>>()
628→        .into_iter()
629→        .rev()
630→        .collect();
631→
632→    if pace_entries.is_empty() {
633→        return;
634→    }
635→
636→    // Get files for each commit
637→    let num_commits = pace_entries.len();
638→    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
639→
640→    for (col, entry) in pace_entries.iter().enumerate() {
641→        let files = zjjrq_files_for_commit(&entry.commit);
642→        for path in files {
643→            if zjjrq_is_infra_file(&path) {
644→                continue;
645→            }
646→            let bare = zjjrq_bare_filename(&path);
647→            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
648→            row[col] = true;
649→        }
650→    }
651→
652→    if file_touches.is_empty() {
653→        println!();
654→        println!("Pace commits: (no project file commits)");
655→        return;
656→    }
657→
658→    println!();
659→    println!("Pace commits (x = commit touched file):");
660→    println!();
661→
662→    // Legend: commit index char, SHA, subject
663→    for (i, entry) in pace_entries.iter().enumerate() {
664→        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
665→        println!("  {} {}  {}", ch, entry.commit, entry.subject);
666→    }
667→    println!();
668→
669→    // Column header line
670→    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
671→    println!("{}", header);
672→
673→    // Group by identical touch pattern
674→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
675→    for (filename, pattern) in &file_touches {
676→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
677→    }
678→    for files in pattern_groups.values_mut() {
679→        files.sort();
680→    }
681→
682→    // Sort: more touches first, then lexicographic
683→    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
684→    sorted.sort_by(|(a, _), (b, _)| {
685→        let ca: usize = a.iter().filter(|&&v| v).count();
686→        let cb: usize = b.iter().filter(|&&v| v).count();
687→        cb.cmp(&ca).then_with(|| a.cmp(b))
688→    });
689→
690→    for (pattern, files) in &sorted {
691→        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
692→        println!("{} {}", bits, files.join(", "));
693→    }
694→}
